import path from 'node:path';

import type { SvgExportParams } from '@projeto-types/relatorios';
import type { SvgCandidate, SvgDirectoryStats, SvgExportResult } from '@prometheus';
import { otimizarSvgLikeSvgo, shouldSugerirOtimizacaoSvg } from '@shared/impar';

export type { SvgCandidate, SvgExportResult };
function formatBytes(bytes: number): string {
if (!Number.isFinite(bytes) || bytes < 0) return String(bytes);
if (bytes < 1024) return `${bytes}B`;
const kb = bytes / 1024;
if (kb < 1024) return `${kb.toFixed(1)}KB`;
const mb = kb / 1024;
return `${mb.toFixed(1)}MB`;
}
/**
* Gera e escreve o relatório de otimização de SVG no diretório de relatórios
*/
export async function exportarRelatorioSvgOtimizacao(params: SvgExportParams): Promise<SvgExportResult> {
const {
entries,
relatoriosDir,
ts
} = params;
const candidatos: SvgCandidate[] = [];
for (const e of entries) {
if (!e || typeof e.relPath !== 'string') continue;
if (!/\.svg$/i.test(e.relPath)) continue;
if (typeof e.content !== 'string') continue;
if (!/<svg\b/i.test(e.content)) continue;
const opt = otimizarSvgLikeSvgo({
svg: e.content
});
const shouldSuggest = opt.changed && opt.originalBytes > opt.optimizedBytes && shouldSugerirOtimizacaoSvg(opt.originalBytes, opt.optimizedBytes);
if (!shouldSuggest) continue;
const savedBytes = opt.originalBytes - opt.optimizedBytes;
candidatos.push({
relPath: e.relPath,
dir: path.posix.dirname(e.relPath),
originalBytes: opt.originalBytes,
optimizedBytes: opt.optimizedBytes,
savedBytes,
mudancas: opt.mudancas,
temViewBox: /\bviewBox\s*=\s*['"][^'"]+['"]/i.test(e.content)
});
}
const totalEconomiaBytes = candidatos.reduce((acc, c) => acc + c.savedBytes, 0);
const porDir = new Map<string, SvgDirectoryStats>();
for (const c of candidatos) {
const key = c.dir;
const existing = porDir.get(key);
if (!existing) {
porDir.set(key, {
count: 1,
totalSaved: c.savedBytes,
exemplos: [c]
});
} else {
existing.count += 1;
existing.totalSaved += c.savedBytes;
if (existing.exemplos.length < 10) existing.exemplos.push(c);
}
}
const outputCaminho = path.join(relatoriosDir, `prometheus-svg-otimizacao-${ts}.json`);
const dirsOrdenados = Array.from(porDir.entries()).sort((a, b) => b[1].totalSaved - a[1].totalSaved);
const topArquivos = [...candidatos].sort((a, b) => b.savedBytes - a.savedBytes).slice(0, 30);

const report = {
  metadata: {
    timestamp: new Date().toISOString(),
    tipo: 'svg-otimizacao'
  },
  resumo: {
    totalArquivos: candidatos.length,
    economiaTotalBytes: totalEconomiaBytes,
    economiaTotalFormatada: formatBytes(totalEconomiaBytes)
  },
  porDiretorio: dirsOrdenados.map(([dir, info]) => ({
    diretorio: dir,
    arquivos: info.count,
    economiaBytes: info.totalSaved,
    economiaFormatada: formatBytes(info.totalSaved)
  })),
  topArquivos
};
const {
promises: fs
} = await import('node:fs');
await fs.mkdir(relatoriosDir, {
recursive: true
});
await fs.writeFile(outputCaminho, JSON.stringify(report, null, 2), 'utf-8');
return {
outputCaminho,
totalArquivos: candidatos.length,
totalEconomiaBytes
};
}

// SPDX-License-Identifier: MIT
/**
 *  Sistema de Filtros para Diagnóstico
 *
 * Gerencia inclusão/exclusão de arquivos para análise
 * - Processa padrões glob
 * - Expande diretórios automaticamente
 * - Gerencia node_modules e outros padrões especiais
 * - Aplica precedência correta (CLI > config > defaults)
 */

import fs from 'node:fs';
import path from 'node:path';

import { config , mesclarConfigExcludes } from '@core/config';
import type { FiltrosProcessados, OpcoesProcessamentoFiltros, TipoLinguagemProjeto } from '@prometheus';

  /* -------------------------- PROCESSAMENTO DE PADRÕES -------------------------- */

/**
 * Processa lista de padrões achatada (vírgulas, espaços)
 *
 * @example
 * processPatternListAchatado(['src/**', 'tests, lib'])
 * // => ['src/**', 'tests', 'lib']
 */
export function processPatternListAchatado(raw: string[] | undefined): string[] {
  if (!raw || raw.length === 0) return [];
  return Array.from(new Set(raw.flatMap(r => r.split(/[\s,]+/)).map(s => s.trim()).filter(Boolean)));
}

/**
 * Processa padrões em grupos (cada elemento da lista é um grupo)
 *
 * @example
 * processPatternGroups(['src/** tests/**', 'lib/**'])
 * // => [['src/**', 'tests/**'], ['lib/**']]
 */
export function processPatternGroups(raw: string[] | undefined): string[][] {
  if (!raw || raw.length === 0) return [];
  return raw.map(grupo => grupo.split(/[\s,]+/).map(s => s.trim()).filter(Boolean)).filter(g => g.length > 0);
}

/**
 * Expande padrões de inclusão (adiciona variantes recursivas)
 *
 * Para padrões sem metacaracteres glob, adiciona:
 * - `pattern/**` (recursivo)
 * - `** /pattern/**` (se não tiver barra)
 *
 * @example
 * expandIncludes(['src', 'lib/*.ts'])
 * // => ['src', 'src/**', '** /src/**', 'lib/*.ts']
 */
export function expandIncludes(list: string[]): string[] {
  const META = /[\\*\?\{\}\[\]]/; // metacaracteres glob
  const out = new Set<string>();
  for (const p of list) {
    out.add(p);

    // Se não tem metacaracteres, é um diretório literal
    if (!META.test(p)) {
      // Remove barras terminais
      const normalized = p.replace(/[\\\/]+$/, '');

      // Adiciona variante recursiva
      out.add(`${normalized}/**`);

      // Se é nome simples (sem barra), adiciona busca em qualquer nível
      if (!p.includes('/') && !p.includes('\\')) {
        out.add(`**/${normalized}/**`);
      }
    }
  }
  return Array.from(out);
}

  /* -------------------------- DETECÇÃO DE TIPO DE PROJETO -------------------------- */

/**
 * Detecta tipo de projeto baseado em arquivos presentes
 */
export function detectarTipoProjeto(baseDir: string = process.cwd()): TipoLinguagemProjeto {
  try {
    // TypeScript
    if (fs.existsSync(path.join(baseDir, 'tsconfig.json')) && fs.existsSync(path.join(baseDir, 'package.json'))) {
      return 'typescript';
    }

    // Node.js
    if (fs.existsSync(path.join(baseDir, 'package.json'))) {
      return 'nodejs';
    }

    // Python
    if (fs.existsSync(path.join(baseDir, 'requirements.txt')) || fs.existsSync(path.join(baseDir, 'pyproject.toml')) || fs.existsSync(path.join(baseDir, 'setup.py'))) {
      return 'python';
    }

    // Java
    if (fs.existsSync(path.join(baseDir, 'pom.xml')) || fs.existsSync(path.join(baseDir, 'build.gradle')) || fs.existsSync(path.join(baseDir, 'build.gradle.kts'))) {
      return 'java';
    }

    // .NET
    const files = fs.readdirSync(baseDir);
    if (files.some(f => f.endsWith('.csproj')) || files.some(f => f.endsWith('.sln'))) {
      return 'dotnet';
    }
    return 'generico';
  } catch {
    return 'generico';
  }
}

  /* -------------------------- PADRÕES DE EXCLUSÃO -------------------------- */

/**
 * Obtém padrões de exclusão padrão baseados em configuração e tipo de projeto
 */
export function getDefaultExcludes(tipoProjeto?: TipoLinguagemProjeto): string[] {
  // Tenta obter do prometheus.config.json
  const configIncluirExcluir = config.INCLUDE_EXCLUDE_RULES;
  if (configIncluirExcluir?.globalExcludeGlob) {
    if (Array.isArray(configIncluirExcluir.globalExcludeGlob) && configIncluirExcluir.globalExcludeGlob.length > 0) {
      return Array.from(new Set(configIncluirExcluir.globalExcludeGlob));
    }
  }

  // Fallback: usa padrões do sistema baseado no tipo de projeto
  const tipo = tipoProjeto || detectarTipoProjeto();
  return mesclarConfigExcludes(null, tipo);
}

  /* -------------------------- CONFIGURAÇÃO DE FILTROS -------------------------- */

/**
 * Processa e aplica filtros CLI
 *
 * Precedência:
 * 1. CLI --exclude (máxima)
 * 2. prometheus.config.json
 * 3. Padrões do sistema (fallback)
 */
export function processarFiltros(opcoes: OpcoesProcessamentoFiltros): FiltrosProcessados {
  const tipoProjeto = detectarTipoProjeto();

  // Processar includes
  const includeGroups = processPatternGroups(opcoes.include);
  const includeFlat = includeGroups.flat();
  const includeExpanded = expandIncludes(includeFlat);

  // Processar excludes
  const excludeFlat = processPatternListAchatado(opcoes.exclude);

  // Determinar padrões de exclusão finais
  let excludePadroes: string[];
  if (excludeFlat.length > 0) {
    // CLI tem precedência
    excludePadroes = excludeFlat;
  } else {
    // Usar defaults do config ou sistema
    excludePadroes = getDefaultExcludes(tipoProjeto);
  }

  // Verificar se node_modules deve ser incluído
  let incluiNodeModules = opcoes.forceIncludeNodeModules || false;
  if (includeFlat.some(p => /node_modules/.test(p))) {
    incluiNodeModules = true;
  }

  // Remover node_modules dos excludes se explicitamente incluído
  if (incluiNodeModules) {
    excludePadroes = excludePadroes.filter(p => !/node_modules/.test(p));
  }

  // Processar flag de testes
  if (opcoes.forceIncludeTests && !includeFlat.some(p => /tests?/.test(p))) {
    includeExpanded.push('tests/**', 'test/**', '**/*.test.*', '**/*.spec.*');
  }
  return {
    includeGroups,
    includeFlat: includeExpanded,
    excludePadroes,
    incluiNodeModules,
    tipoProjeto
  };
}

/**
 * Aplica filtros processados ao config global
 */
export function aplicarFiltrosAoConfig(filtros: FiltrosProcessados): void {
  // Configurar includes
  if (filtros.includeFlat.length > 0) {
    config.CLI_INCLUDE_GROUPS = filtros.includeGroups;
    config.CLI_INCLUDE_PATTERNS = filtros.includeFlat;
  } else {
    config.CLI_INCLUDE_GROUPS = [];
    config.CLI_INCLUDE_PATTERNS = [];
  }

  // Configurar excludes
  config.CLI_EXCLUDE_PATTERNS = filtros.excludePadroes;
}

/**
 * API simplificada: processa e aplica filtros em uma única chamada
 */
export function configurarFiltros(opcoes: OpcoesProcessamentoFiltros): FiltrosProcessados {
  const filtros = processarFiltros(opcoes);
  aplicarFiltrosAoConfig(filtros);
  return filtros;
}

// SPDX-License-Identifier: MIT
/**
 *  Arquetipo Handler
 *
 * Gerencia detecção e análise de estrutura do projeto
 * - Detecta arquetipos com timeout
 * - Identifica padrões de projeto
 * - Salva arquetipos personalizados
 * - Formata resultados
 */

import { detectarArquetipos } from '@analistas/detectores';
import { config } from '@core/config';
import { messages } from '@core/messages';
import type { ArquetipoOptions, ArquetipoResult, FileEntryWithAst } from '@prometheus';

const log = messages.log;

// Re-export para compatibilidade
export type { ArquetipoOptions, ArquetipoResult };

/**
 * Timeout padrão para detecção (em ms)
 */
const PADRAO_TEMPO_LIMITE_MS = process.env.VITEST ? 1000 : 30000;

/**
 * Executa detecção de arquetipos com timeout
 */
export async function executarDeteccaoArquetipos(entries: FileEntryWithAst[], baseDir: string, options: ArquetipoOptions): Promise<ArquetipoResult> {
  // Se desabilitado, retorna resultado vazio
  if (!options.enabled) {
    return {
      executado: false
    };
  }
  try {
    // Log de início (se não silencioso)
    if (!options.silent) {
      log.info(messages.MENSAGENS_ARQUETIPOS.detectando);
    }

    // Preparar contexto
    const ctx = {
      arquivos: entries,
      baseDir
    };

    // Executar detecção com timeout
    const timeoutMs = options.timeout || PADRAO_TEMPO_LIMITE_MS;
    const resultado = await executarComTimeout(detectarArquetipos(ctx, baseDir), timeoutMs);

    // Se timeout ou erro, retorna resultado parcial
    if (!resultado) {
      if (!options.silent) {
        log.aviso(messages.CliArquetipoHandlerMensagens.timeoutDeteccao);
      }
      return {
        executado: true,
        erro: 'timeout'
      };
    }

    // Processar resultado
    const arquetipos = resultado.candidatos || [];
    const principal = arquetipos.length > 0 ? arquetipos[0] : undefined; // Log de resultado (se não silencioso)
    if (!options.silent && principal) {
      log.info(messages.MENSAGENS_ARQUETIPOS.identificado(principal.nome, principal.confidence));
      if (arquetipos.length > 1) {
        log.info(messages.MENSAGENS_ARQUETIPOS.multiplos(arquetipos.length));
      }
    }

    // Salvar se solicitado
    let salvo = false;
    if (options.salvar && resultado) {
      salvo = await salvarArquetipo(resultado, baseDir, options.silent);
    }
    return {
      executado: true,
      arquetipos: arquetipos.map(a => ({
        tipo: a.nome,
        confianca: a.confidence,
        caracteristicas: a.matchedRequired || []
      })),
      principal: principal ? {
        tipo: principal.nome,
        confianca: principal.confidence
      } : undefined,
      salvo
    };
  } catch (erro) {
    const mensagem = erro instanceof Error ? erro.message : String(erro);
    if (!options.silent) {
      log.aviso(messages.CliArquetipoHandlerMensagens.erroDeteccao(mensagem));
    }

    // Em DEV_MODE, log mais detalhado
    if (config.DEV_MODE) {
      console.error(messages.CliArquetipoHandlerMensagens.devErroPrefixo, erro);
    }
    return {
      executado: true,
      erro: mensagem
    };
  }
}

/**
 * Executa função com timeout
 */
async function executarComTimeout<T>(promise: Promise<T>, timeoutMs: number): Promise<T | undefined> {
  try {
    const timeoutPromise = new Promise<undefined>(resolve => setTimeout(() => resolve(undefined), timeoutMs));
    return (await Promise.race([promise, timeoutPromise])) as T | undefined;
  } catch {
    return undefined;
  }
}

/**
 * Salva arquetipo personalizado
 */
async function salvarArquetipo(resultado: Awaited<ReturnType<typeof detectarArquetipos>>, baseDir: string, silent?: boolean): Promise<boolean> {
  try {
    if (!silent) {
      log.info(messages.MENSAGENS_ARQUETIPOS.salvando);
    }

    // Importação dinâmica para evitar dependências circulares
    const fs = await import('node:fs/promises');
    const path = await import('node:path');

    // Preparar dados do arquetipo
    const arquetipo = {
      timestamp: new Date().toISOString(),
      projeto: path.basename(baseDir),
      arquetipos: resultado.candidatos,
      baseline: resultado.baseline,
      drift: resultado.drift
    };

    // Salvar em arquivo
    const outputCaminho = path.join(baseDir, 'prometheus.repo.arquetipo.json');
    await fs.writeFile(outputCaminho, JSON.stringify(arquetipo, null, 2), 'utf-8');
    if (!silent) {
      log.sucesso(messages.MENSAGENS_ARQUETIPOS.salvo(outputCaminho));
    }
    return true;
  } catch (erro) {
    const mensagem = erro instanceof Error ? erro.message : String(erro);
    if (!silent) {
      log.aviso(messages.CliArquetipoHandlerMensagens.falhaSalvar(mensagem));
    }
    return false;
  }
}

/**
 * Formata resultado de arquetipos para JSON
 */
export function formatarArquetiposParaJson(result: ArquetipoResult): Record<string, unknown> {
  if (!result.executado) {
    return {
      executado: false
    };
  }
  if (result.erro) {
    return {
      executado: true,
      erro: result.erro
    };
  }
  return {
    executado: true,
    arquetipos: result.arquetipos || [],
    principal: result.principal || null,
    salvo: result.salvo || false
  };
}

/**
 * Gera sugestões baseadas no arquetipo detectado
 */
export function gerarSugestoesArquetipo(result: ArquetipoResult): string[] {
  const sugestoes: string[] = [];
  if (!result.executado || !result.principal) {
    return sugestoes;
  }
  const {
    tipo,
    confianca
  } = result.principal;

  // Sugestões baseadas no tipo de projeto
  switch (tipo.toLowerCase()) {
    case 'monorepo':
      sugestoes.push(' Monorepo detectado: considere usar filtros por workspace');
      sugestoes.push(' Use --include packages/* para analisar workspaces específicos');
      break;
    case 'biblioteca':
    case 'library':
      sugestoes.push(' Biblioteca detectada: foque em exports públicos e documentação');
      sugestoes.push(' Use --guardian para verificar API pública');
      break;
    case 'cli':
    case 'cli-tool':
      sugestoes.push(' CLI detectado: priorize testes de comandos e flags');
      break;
    case 'api':
    case 'api-rest':
    case 'api-server':
      sugestoes.push(' API detectada: foque em endpoints e contratos');
      sugestoes.push(' Considere testes de integração para rotas');
      break;
    case 'frontend':
    case 'web-app':
      sugestoes.push(' Frontend detectado: priorize componentes e state management');
      break;
  }

  // Sugestão baseada em confiança
  if (confianca < 70) {
    sugestoes.push('  Confiança baixa na detecção: estrutura pode ser híbrida');
    sugestoes.push(' Use --criar-arquetipo --salvar-arquetipo para personalizar');
  }
  return sugestoes;
}

