    for (const k of Object.keys(obj)) {
      const keyCaminho = prefix ? `${prefix}.${k}` : k;
      const envNome = `PROMETHEUS_${keyCaminho.replace(/\./g, '_').toUpperCase()}`;
      const currentVal = (obj as Record<string, unknown>)[k];
