    MAX_LINHAS_ARQUIVO: 300
  },

  // Limites para detecção de arquivos fantasmas (ghost files)
  GUARDIAN: {
    DIAS_INATIVIDADE_GHOST: 45
  },

  // Thresholds de segurança e entropia
  SEGURANCA: {
